#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin>>n;
    if(n%2==1){
        cout<<-1;return 0;
    }
    int a[1000]={0};
    int c=1;
    while(n){
        a[c++]=n%2;
        n/=2;
    }
    c--;
    for(int i=c;i>1;i--){
        if(a[i]){
			int t=pow(2,i-1);
			printf("%d ",t);
		} 
    } 
    return 0;
}
